def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = np.inf if item > 0 else 0
            continue
        ratio = 0 if capacity == 0 else item / capacity
        if ratio == 0:
            if item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
            continue
        if ratio > 2:
            base = ratio ** 4
            penalty = 0
            factor = 0.5
            for k in range(1, 6):
                penalty += (ratio ** (2 * k)) / (k * (k + 1)) * factor
                factor /= 2
            priorities[i] = base + penalty
            if ratio > 3:
                reduction = 0
                for p in range(1, 5):
                    reduction += (ratio ** (-p)) * p
                priorities[i] -= reduction
        elif 1 < ratio <= 2:
            priorities[i] = (ratio ** 3) * 7
            additive = 0
            for q in range(5):
                term = ((-1)**q) * (ratio ** (q + 1)) / (q + 2)
                additive += term
            priorities[i] += abs(additive) * 3
        elif 0 < ratio <= 1:
            score = 0
            sign = 1
            for j in range(1, 8):
                if j % 2 == 0:
                    sign = -1
                else:
                    sign = 1
                power_term = (ratio ** j) / (j + 1)
                score += sign * power_term
            multiplier = 20 if ratio < 0.25 else 12 if ratio < 0.5 else 8 if ratio < 0.75 else 4
            priorities[i] = abs(score) * multiplier
            if ratio > 0.85:
                extra = 0
                for m in range(1, 5):
                    extra += ((ratio ** m) * (m + 1)) / (m * 2)
                priorities[i] += extra * 1.5
        else:
            if item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
        if priorities[i] != np.inf:
            adjust = 0
            for z in range(1, 4):
                adjust += ((-1) ** z) * ((item + capacity) / (z + 1)) ** (z / 2)
            priorities[i] += abs(adjust) * 0.7
    return priorities
